<template><main class="page"><h1>房间列表</h1><GameButton @click="roomStore.refresh">刷新</GameButton><EmptyState v-if="!roomStore.rooms.length" title="暂无房间" :description="messages.emptyRooms" /><section class="grid"><RoomCard v-for="room in roomStore.rooms" :key="room.id" :room="room" @join="join" /></section></main></template><script setup lang="ts">import { useRouter } from 'vue-router'; import { useRoomStore } from '../stores/roomStore'; import GameButton from '../components/common/GameButton.vue'; import RoomCard from '../components/common/RoomCard.vue'; import EmptyState from '../components/common/EmptyState.vue'; import { messages } from '../constants/messages'; const router=useRouter(); const roomStore=useRoomStore(); function join(id:string){roomStore.join(id);router.push('/room/'+id)}</script>
